module RefModule (
    input wire D,
    input wire EN,
    output reg Q,
    output reg Q_not
);
    reg unused_master_Q;

    always @(posedge EN) begin
        unused_master_Q <= D;
    end

    always @(negedge EN) begin
        Q <= unused_master_Q;
        Q_not <= ~unused_master_Q;
    end
endmodule
